};

const roleOrder: GuildRole[] = ['LEADER', 'VICE_LEADER', 'ELDER', 'MEMBER', 'RECRUIT'];

export default function GuildMembersPage() {
  // Sort members by role hierarchy, then by contribution XP
  const sortedMembers = [...mockMembers].sort((a, b) => {
