function formatXp(xp: number): string {
  if (xp >= 1000000) return `${(xp / 1000000).toFixed(1)}M`;
  if (xp >= 1000) return `${(xp / 1000).toFixed(1)}K`;
  return xp.toString();
}

function formatLastSeen(date: Date): string {
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMinutes = Math.floor(diffMs / (1000 * 60));
  const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffMinutes < 60) return `${diffMinutes}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  return `${diffDays}d ago`;
}

function CrownIcon({ className }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="currentColor" stroke="none">
      <path d="m2 4 3 12h14l3-12-6 7-4-7-4 7-6-7z" />
    </svg>
  );
}

import {
  Injectable,
  Inject,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
  ConflictException,
} from '@nestjs/common';
import { PrismaClient } from '@mmorpg/database';
import { GuildRole } from '@mmorpg/types';
import Redis from 'ioredis';
import { GUILD_REDIS_CLIENT } from './guilds.module';

/** Maximum pending invitations per guild */
const MAX_PENDING_INVITATIONS = 10;

/** Invitation TTL in seconds (48 hours) */
const INVITATION_TTL_SECONDS = 48 * 60 * 60;

/** Maximum guild storage slots */
const MAX_STORAGE_SLOTS = 200;

/** Maximum pinned announcements */
const MAX_PINNED_ANNOUNCEMENTS = 3;

/** Valid war durations in hours */
const VALID_WAR_DURATIONS = [24, 48, 72];

/** Guild creation requirements */
const MIN_LEVEL_FOR_GUILD = 30;
const MIN_GOLD_FOR_GUILD = 100_000;

/** Roles that can promote/demote */
const MANAGEMENT_ROLES: GuildRole[] = [GuildRole.LEADER, GuildRole.VICE_LEADER];

/** Role hierarchy (higher index = higher rank) */
const ROLE_HIERARCHY: GuildRole[] = [
  GuildRole.RECRUIT,
  GuildRole.MEMBER,
  GuildRole.ELDER,
  GuildRole.VICE_LEADER,
  GuildRole.LEADER,
];

export interface CreateGuildInput {
  name: string;
  description?: string;
  emblem?: string;
  recruitmentOpen?: boolean;
}

export interface CreateAnnouncementInput {
  title: string;
  content: string;
  isPinned?: boolean;
  priority?: 'LOW' | 'NORMAL' | 'HIGH' | 'URGENT';
}

export interface GuildWarInput {
  targetGuildId: string;
  duration: number;
  objectives: string;
}

@Injectable()
export class GuildsService {
  constructor(
    private readonly prisma: PrismaClient,
    @Inject(GUILD_REDIS_CLIENT) private readonly redis: Redis,
  ) {}

  /**
   * Create a new guild. Player must have a character at level 30+ and 100,000+ gold.
   * Gold is deducted upon creation.
   */
  async createGuild(userId: string, input: CreateGuildInput) {
    // Check if player has a character at level 30+
    const highestCharacter = await this.prisma.character.findFirst({
      where: { userId, deletedAt: null, level: { gte: MIN_LEVEL_FOR_GUILD } },
      orderBy: { level: 'desc' },
    });

    if (!highestCharacter) {
      throw new BadRequestException(
        `You need at least one character at level ${MIN_LEVEL_FOR_GUILD} or higher to create a guild`,
      );
    }

    // Check gold balance
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { goldBalance: true },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    if (Number(user.goldBalance) < MIN_GOLD_FOR_GUILD) {
      throw new BadRequestException(
        `You need at least ${MIN_GOLD_FOR_GUILD.toLocaleString()} gold to create a guild`,
      );
    }

    // Check if user is already a guild leader
    const existingLeadership = await this.prisma.guildMember.findFirst({
      where: { userId, role: GuildRole.LEADER },
      include: { guild: { select: { deletedAt: true } } },
    });

    if (existingLeadership && !existingLeadership.guild.deletedAt) {
      throw new ConflictException('You are already the leader of a guild');
    }

    // Check guild name uniqueness
    const existingGuild = await this.prisma.guild.findFirst({
      where: { name: input.name, deletedAt: null },
    });

    if (existingGuild) {
      throw new ConflictException('A guild with this name already exists');
    }

    // Create guild and deduct gold in a transaction
    const guild = await this.prisma.$transaction(async (tx) => {
      // Deduct gold
      await tx.user.update({
        where: { id: userId },
        data: { goldBalance: { decrement: MIN_GOLD_FOR_GUILD } },
      });

      // Create guild
      const newGuild = await tx.guild.create({
        data: {
          name: input.name,
          description: input.description || null,
          emblem: input.emblem || null,
          recruitmentOpen: input.recruitmentOpen ?? true,
        },
      });

      // Add creator as leader
      await tx.guildMember.create({
        data: {
          guildId: newGuild.id,
          userId,
          role: GuildRole.LEADER,
        },
      });

      return newGuild;
    });

    // Log activity
    await this.logActivity(guild.id, userId, 'GUILD_CREATED', `Guild "${guild.name}" created`);

    return {
      id: guild.id,
      name: guild.name,
      emblem: guild.emblem,
      description: guild.description,
      level: guild.level,
      experience: guild.experience.toString(),
      recruitmentOpen: guild.recruitmentOpen,
      maxMembers: guild.maxMembers,
      createdAt: guild.createdAt.toISOString(),
    };
  }

  /**
   * Get guild profile with members, level, and ranking.
   */
  async getGuild(guildId: string) {
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
      include: {
        members: {
          include: {
            user: {
              select: { id: true, username: true },
            },
          },
          orderBy: [{ role: 'asc' }, { joinedAt: 'asc' }],
        },
      },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // Get ranking position from Redis
    const rankingScore = await this.redis.zscore('ranking:top_guild', guildId);
    const rankingPosition = rankingScore
      ? (await this.redis.zrevrank('ranking:top_guild', guildId))
      : null;

    return {
      id: guild.id,
      name: guild.name,
      emblem: guild.emblem,
      description: guild.description,
      level: guild.level,
      experience: guild.experience.toString(),
      recruitmentOpen: guild.recruitmentOpen,
      maxMembers: guild.maxMembers,
      memberCount: guild.members.length,
      rankingPosition: rankingPosition !== null ? rankingPosition + 1 : null,
      createdAt: guild.createdAt.toISOString(),
      updatedAt: guild.updatedAt.toISOString(),
      members: guild.members.map((m) => ({
        id: m.id,
        userId: m.user.id,
        username: m.user.username,
        role: m.role,
        joinedAt: m.joinedAt.toISOString(),
        contributionXp: m.contributionXp.toString(),
      })),
    };
  }

  /**
   * Invite a player to the guild. Stored in Redis with 48h TTL.
   * Max 10 pending invitations per guild.
   */
  async inviteMember(guildId: string, targetUserId: string, invitedByUserId: string) {
    // Verify guild exists
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // Verify target user exists
    const targetUser = await this.prisma.user.findUnique({
      where: { id: targetUserId },
      select: { id: true, username: true },
    });

    if (!targetUser) {
      throw new NotFoundException('Target user not found');
    }

    // Check if target is already a member
    const existingMembership = await this.prisma.guildMember.findUnique({
      where: { guildId_userId: { guildId, userId: targetUserId } },
    });

    if (existingMembership) {
      throw new ConflictException('User is already a member of this guild');
    }

    // Check pending invitation count
    const pendingKey = `guild:${guildId}:invitations`;
    const pendingCount = await this.redis.scard(pendingKey);

    if (pendingCount >= MAX_PENDING_INVITATIONS) {
      throw new BadRequestException(
        `Maximum of ${MAX_PENDING_INVITATIONS} pending invitations reached`,
      );
    }

    // Check if user already has a pending invitation
    const invitationKey = `guild:${guildId}:invite:${targetUserId}`;
    const existingInvite = await this.redis.get(invitationKey);

    if (existingInvite) {
      throw new ConflictException('An invitation is already pending for this user');
    }

    // Create invitation in Redis
    const invitationId = crypto.randomUUID();
    const invitation = {
      id: invitationId,
      guildId,
      guildName: guild.name,
      invitedUserId: targetUserId,
      invitedByUserId,
      createdAt: new Date().toISOString(),
      expiresAt: new Date(Date.now() + INVITATION_TTL_SECONDS * 1000).toISOString(),
    };

    // Store invitation with TTL
    await this.redis.set(invitationKey, JSON.stringify(invitation), 'EX', INVITATION_TTL_SECONDS);

    // Track in pending set (also with TTL)
    await this.redis.sadd(pendingKey, targetUserId);
    await this.redis.expire(pendingKey, INVITATION_TTL_SECONDS);

    // Log activity
    await this.logActivity(
      guildId,
      invitedByUserId,
      'MEMBER_INVITED',
      `Invited user ${targetUser.username}`,
    );

    return invitation;
  }

  /**
   * Update a guild member's role. Only Leader/Vice Leader can promote/demote.
   * Cannot promote above own role.
   */
  async updateMemberRole(
    guildId: string,
    memberId: string,
    newRole: GuildRole,
    actorUserId: string,
  ) {
    // Get actor's membership
    const actorMembership = await this.prisma.guildMember.findUnique({
      where: { guildId_userId: { guildId, userId: actorUserId } },
    });

    if (!actorMembership) {
      throw new ForbiddenException('You are not a member of this guild');
    }

    // Only Leader/Vice Leader can manage roles
    if (!MANAGEMENT_ROLES.includes(actorMembership.role as GuildRole)) {
      throw new ForbiddenException('Only Leader or Vice Leader can manage roles');
    }

    // Get target member
    const targetMember = await this.prisma.guildMember.findFirst({
      where: { id: memberId, guildId },
      include: { user: { select: { username: true } } },
    });

    if (!targetMember) {
      throw new NotFoundException('Guild member not found');
    }

    // Cannot change own role
    if (targetMember.userId === actorUserId) {
      throw new BadRequestException('You cannot change your own role');
    }

    // Cannot promote to LEADER (leadership transfer is separate)
    if (newRole === GuildRole.LEADER) {
      throw new BadRequestException('Leadership transfer must use a dedicated endpoint');
    }

    const actorRoleIndex = ROLE_HIERARCHY.indexOf(actorMembership.role as GuildRole);
    const targetCurrentRoleIndex = ROLE_HIERARCHY.indexOf(targetMember.role as GuildRole);
    const newRoleIndex = ROLE_HIERARCHY.indexOf(newRole);

    // Cannot promote above own role
    if (newRoleIndex >= actorRoleIndex) {
      throw new ForbiddenException('Cannot promote a member to or above your own role');
    }

    // Cannot demote someone at or above own role
    if (targetCurrentRoleIndex >= actorRoleIndex) {
      throw new ForbiddenException('Cannot change the role of a member at or above your rank');
    }

    // Update role
    await this.prisma.guildMember.update({
      where: { id: memberId },
      data: { role: newRole },
    });

    // Log activity
    const action = newRoleIndex > targetCurrentRoleIndex ? 'MEMBER_PROMOTED' : 'MEMBER_DEMOTED';
    await this.logActivity(
      guildId,
      actorUserId,
      action,
      `${targetMember.user.username} role changed from ${targetMember.role} to ${newRole}`,
    );

    return { memberId, newRole };
  }

  /**
   * Initiate a guild war. Only Leader/Vice Leader can initiate.
   * Duration options: 24h, 48h, 72h.
   */
  async initiateWar(guildId: string, input: GuildWarInput, actorUserId: string): Promise<{
    id: string;
    initiatorGuildId: string;
    initiatorGuildName: string;
    defenderGuildId: string;
    defenderGuildName: string;
    initiatorScore: number;
    defenderScore: number;
    startedAt: string | null;
    endsAt: string;
    status: string;
    duration: number;
    objectives: unknown;
  }> {
    // Validate duration
    if (!VALID_WAR_DURATIONS.includes(input.duration)) {
      throw new BadRequestException(
        `War duration must be one of: ${VALID_WAR_DURATIONS.join(', ')} hours`,
      );
    }

    // Verify initiator guild exists
    const initiatorGuild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!initiatorGuild) {
      throw new NotFoundException('Initiator guild not found');
    }

    // Verify target guild exists
    const targetGuild = await this.prisma.guild.findFirst({
      where: { id: input.targetGuildId, deletedAt: null },
    });

    if (!targetGuild) {
      throw new NotFoundException('Target guild not found');
    }

    // Cannot war yourself
    if (guildId === input.targetGuildId) {
      throw new BadRequestException('A guild cannot declare war on itself');
    }

    // Check for existing active war between these guilds
    const existingWar = await this.prisma.guildWar.findFirst({
      where: {
        OR: [
          { initiatorId: guildId, defenderId: input.targetGuildId },
          { initiatorId: input.targetGuildId, defenderId: guildId },
        ],
        status: { in: ['PENDING', 'ACTIVE'] },
      },
    });

    if (existingWar) {
      throw new ConflictException('There is already an active or pending war between these guilds');
    }

    // Create war
    const startedAt = new Date();
    const endsAt = new Date(startedAt.getTime() + input.duration * 60 * 60 * 1000);

    const war = await this.prisma.guildWar.create({
      data: {
        initiatorId: guildId,
        defenderId: input.targetGuildId,
        status: 'ACTIVE',
        duration: input.duration,
        startedAt,
        objectives: { description: input.objectives },
      },
    });

    // Log activity for both guilds
    await this.logActivity(
      guildId,
      actorUserId,
      'WAR_INITIATED',
      `Guild war initiated against "${targetGuild.name}" for ${input.duration}h`,
    );

    await this.logActivity(
      input.targetGuildId,
      actorUserId,
      'WAR_RECEIVED',
      `Guild war declared by "${initiatorGuild.name}" for ${input.duration}h`,
    );

    return {
      id: war.id,
      initiatorGuildId: guildId,
      initiatorGuildName: initiatorGuild.name,
      defenderGuildId: input.targetGuildId,
      defenderGuildName: targetGuild.name,
      initiatorScore: war.initiatorScore,
      defenderScore: war.defenderScore,
      startedAt: war.startedAt?.toISOString() ?? null,
      endsAt: endsAt.toISOString(),
      status: war.status,
      duration: war.duration,
      objectives: war.objectives,
    };
  }

  /**
   * Get guild storage with role-based access.
   * Elder+ gets full access, Member gets limited access.
   */
  async getGuildStorage(guildId: string, userId: string) {
    // Verify guild exists
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // Get member's role
    const membership = await this.prisma.guildMember.findUnique({
      where: { guildId_userId: { guildId, userId } },
    });

    if (!membership) {
      throw new ForbiddenException('You are not a member of this guild');
    }

    const memberRoleIndex = ROLE_HIERARCHY.indexOf(membership.role as GuildRole);
    const elderRoleIndex = ROLE_HIERARCHY.indexOf(GuildRole.ELDER);

    // Recruits cannot access storage at all
    if (membership.role === GuildRole.RECRUIT) {
      throw new ForbiddenException('Recruits do not have access to guild storage');
    }

    const storageItems = await this.prisma.guildStorageItem.findMany({
      where: { guildId },
      orderBy: [{ itemCategory: 'asc' }, { depositedAt: 'desc' }],
    });

    // Members get limited access (can only see, not full details)
    const hasFullAccess = memberRoleIndex >= elderRoleIndex;

    return {
      guildId,
      totalSlots: MAX_STORAGE_SLOTS,
      usedSlots: storageItems.length,
      hasFullAccess,
      items: storageItems.map((item) => ({
        id: item.id,
        guildId: item.guildId,
        itemId: item.itemId,
        itemName: item.itemName,
        itemCategory: item.itemCategory,
        itemRarity: item.itemRarity,
        quantity: item.quantity,
        depositedBy: hasFullAccess ? item.depositedBy : undefined,
        depositedAt: item.depositedAt.toISOString(),
      })),
    };
  }

  /**
   * Post a guild announcement with pinning and priority levels.
   * Max 3 pinned announcements.
   */
  async postAnnouncement(guildId: string, authorId: string, input: CreateAnnouncementInput) {
    // Verify guild exists
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // If pinning, check max pinned count
    if (input.isPinned) {
      const pinnedCount = await this.prisma.guildAnnouncement.count({
        where: { guildId, isPinned: true },
      });

      if (pinnedCount >= MAX_PINNED_ANNOUNCEMENTS) {
        throw new BadRequestException(
          `Maximum of ${MAX_PINNED_ANNOUNCEMENTS} pinned announcements reached. Unpin an existing announcement first.`,
        );
      }
    }

    const announcement = await this.prisma.guildAnnouncement.create({
      data: {
        guildId,
        authorId,
        title: input.title,
        content: input.content,
        isPinned: input.isPinned ?? false,
        priority: input.priority ?? 'NORMAL',
      },
    });

    // Log activity
    await this.logActivity(
      guildId,
      authorId,
      'ANNOUNCEMENT_POSTED',
      `Announcement "${input.title}" posted`,
    );

    // Get author name for response
    const author = await this.prisma.user.findUnique({
      where: { id: authorId },
      select: { username: true },
    });

    return {
      id: announcement.id,
      guildId: announcement.guildId,
      authorId: announcement.authorId,
      authorName: author?.username ?? 'Unknown',
      title: announcement.title,
      content: announcement.content,
      isPinned: announcement.isPinned,
      priority: announcement.priority,
      createdAt: announcement.createdAt.toISOString(),
    };
  }

  /**
   * Get guild announcements.
   */
  async getAnnouncements(guildId: string) {
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    const announcements = await this.prisma.guildAnnouncement.findMany({
      where: { guildId },
      orderBy: [{ isPinned: 'desc' }, { createdAt: 'desc' }],
    });

    // Get author names
    const authorIds = [...new Set(announcements.map((a) => a.authorId))];
    const authors = await this.prisma.user.findMany({
      where: { id: { in: authorIds } },
      select: { id: true, username: true },
    });
    const authorMap = new Map(authors.map((a) => [a.id, a.username]));

    return announcements.map((a) => ({
      id: a.id,
      guildId: a.guildId,
      authorId: a.authorId,
      authorName: authorMap.get(a.authorId) ?? 'Unknown',
      title: a.title,
      content: a.content,
      isPinned: a.isPinned,
      priority: a.priority,
      createdAt: a.createdAt.toISOString(),
    }));
  }

  /**
   * Get guild activity log.
   */
  async getActivityLog(guildId: string, page: number = 1, pageSize: number = 20) {
    const guild = await this.prisma.guild.findFirst({
      where: { id: guildId, deletedAt: null },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    const key = `guild:${guildId}:activity`;
    const start = (page - 1) * pageSize;
    const stop = start + pageSize - 1;

    const entries = await this.redis.lrange(key, start, stop);
    const total = await this.redis.llen(key);

    return {
      data: entries.map((entry) => JSON.parse(entry)),
      meta: {
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
        hasNext: page * pageSize < total,
        hasPrev: page > 1,
      },
    };
  }

  /**
   * Log a guild activity to Redis.
   */
  private async logActivity(
    guildId: string,
    actorId: string,
    action: string,
    details: string,
  ): Promise<void> {
    const key = `guild:${guildId}:activity`;

    // Get actor name
    const actor = await this.prisma.user.findUnique({
      where: { id: actorId },
      select: { username: true },
    });

    const entry = {
      id: crypto.randomUUID(),
      guildId,
      actorId,
      actorName: actor?.username ?? 'Unknown',
      action,
      details,
      createdAt: new Date().toISOString(),
    };

    // Push to the front of the list (most recent first)
    await this.redis.lpush(key, JSON.stringify(entry));

    // Keep only last 1000 entries
    await this.redis.ltrim(key, 0, 999);
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Param,
  Body,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { GuildsService, CreateGuildInput, CreateAnnouncementInput, GuildWarInput } from './guilds.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { GuildRolesGuard } from '../../common/guards/guild-roles.guard';
import { GuildRoles } from '../../common/decorators/guild-roles.decorator';
import { GuildRole } from '@mmorpg/types';

@Controller('api/guilds')
@UseGuards(JwtAuthGuard)
export class GuildsController {
  constructor(private readonly guildsService: GuildsService) {}

  /**
   * POST /api/guilds
   * Create a new guild. Requires level 30+ character and 100,000+ gold.
   */
  @Post()
  async createGuild(@Body() body: CreateGuildInput, @Request() req: any) {
    const userId = req.user.userId;
    return this.guildsService.createGuild(userId, body);
  }

  /**
   * GET /api/guilds/:id
   * Get guild profile with members, level, and ranking.
   */
  @Get(':id')
  async getGuild(@Param('id') id: string) {
    return this.guildsService.getGuild(id);
  }

  /**
   * POST /api/guilds/:id/invite
   * Invite a player to the guild. Requires Elder+ role.
   */
  @Post(':id/invite')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(GuildRole.LEADER, GuildRole.VICE_LEADER, GuildRole.ELDER)
  async inviteMember(
    @Param('id') id: string,
    @Body('targetUserId') targetUserId: string,
    @Request() req: any,
  ) {
    const invitedByUserId = req.user.userId;
    return this.guildsService.inviteMember(id, targetUserId, invitedByUserId);
  }

  /**
   * PATCH /api/guilds/:id/members/:memberId/role
   * Update a guild member's role. Requires Leader or Vice Leader role.
   */
  @Patch(':id/members/:memberId/role')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(GuildRole.LEADER, GuildRole.VICE_LEADER)
  async updateMemberRole(
    @Param('id') id: string,
    @Param('memberId') memberId: string,
    @Body('role') role: GuildRole,
    @Request() req: any,
  ) {
    const actorUserId = req.user.userId;
    return this.guildsService.updateMemberRole(id, memberId, role, actorUserId);
  }

  /**
   * POST /api/guilds/:id/war
   * Initiate a guild war. Requires Leader or Vice Leader role.
   */
  @Post(':id/war')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(GuildRole.LEADER, GuildRole.VICE_LEADER)
  async initiateWar(
    @Param('id') id: string,
    @Body() body: GuildWarInput,
    @Request() req: any,
  ) {
    const actorUserId = req.user.userId;
    return this.guildsService.initiateWar(id, body, actorUserId);
  }

  /**
   * GET /api/guilds/:id/storage
   * Get guild storage. Access level depends on guild role.
   */
  @Get(':id/storage')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(GuildRole.LEADER, GuildRole.VICE_LEADER, GuildRole.ELDER, GuildRole.MEMBER)
  async getGuildStorage(@Param('id') id: string, @Request() req: any) {
    const userId = req.user.userId;
    return this.guildsService.getGuildStorage(id, userId);
  }

  /**
   * POST /api/guilds/:id/announcements
   * Post a guild announcement. Requires Elder+ role.
   */
  @Post(':id/announcements')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(GuildRole.LEADER, GuildRole.VICE_LEADER, GuildRole.ELDER)
  async postAnnouncement(
    @Param('id') id: string,
    @Body() body: CreateAnnouncementInput,
    @Request() req: any,
  ) {
    const authorId = req.user.userId;
    return this.guildsService.postAnnouncement(id, authorId, body);
  }

  /**
   * GET /api/guilds/:id/announcements
   * Get guild announcements.
   */
  @Get(':id/announcements')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(
    GuildRole.LEADER,
    GuildRole.VICE_LEADER,
    GuildRole.ELDER,
    GuildRole.MEMBER,
    GuildRole.RECRUIT,
  )
  async getAnnouncements(@Param('id') id: string) {
    return this.guildsService.getAnnouncements(id);
  }

  /**
   * GET /api/guilds/:id/activity
   * Get guild activity log. Requires Member+ role.
   */
  @Get(':id/activity')
  @UseGuards(GuildRolesGuard)
  @GuildRoles(
    GuildRole.LEADER,
    GuildRole.VICE_LEADER,
    GuildRole.ELDER,
    GuildRole.MEMBER,
  )
  async getActivityLog(
    @Param('id') id: string,
    @Query('page') page?: string,
    @Query('pageSize') pageSize?: string,
  ) {
    return this.guildsService.getActivityLog(
      id,
      page ? parseInt(page, 10) : 1,
      pageSize ? parseInt(pageSize, 10) : 20,
    );
  }
